// 1. Dados do Login (Onde está o Token)
const loginData = $input.item.json;

// 2. Busca o Webhook de forma absoluta (isso evita o n8n se perder)
const dadosWebhook = $items("Webhook1")[0].json;

// 3. Tenta buscar o channel_id que veio do Insomnia
let channelId = dadosWebhook.body?.channel_id || dadosWebhook.channel_id;

// 4. PLANO B (SALVA-VIDAS): Se não veio no Insomnia, usa o ID padrão do seu print
if (!channelId) {
    channelId = "67e6b384c5e6300019ecdacb"; 
}

// 5. Junta tudo e passa para frente
return {
    json: {
        channel_id: channelId,
        token: loginData.token
    }
};

const itensWebhook = $items("Webhook1");
const dadosLogin = $items("Login")[0].json;

return itensWebhook.map(item => {
    const corpo = item.json.body || item.json;

    // 1. Telefone
    let foneRaw = corpo.platform_id || corpo.phone || "";
    let platform_id = foneRaw.toString().replace(/\D/g, "");
    if (platform_id && !platform_id.startsWith("55")) platform_id = "55" + platform_id;

    // 2. Dados da mensagem
    const textoOriginal = (corpo.text || "").toString();
    const textoLower = textoOriginal.toLowerCase();
    const nomeCliente = corpo.customerName || "Cliente";
    const linkExtraido = textoOriginal.match(/https?:\/\/\S+/)?.[0] || "";

    // 3. LÓGICA AUTOMÁTICA COM SEUS TEMPLATES REAIS
    let templateEscolhido = "";
    let placeholders = [];

    if (textoLower.includes("folha") || textoLower.includes("pagamento")) {
        templateEscolhido = "informacoes_folha"; // Nome real do seu arquivo
        placeholders = [nomeCliente]; // Este template só tem 1 variável
    } 
    else if (textoLower.includes("certificado") || textoLower.includes("vídeo")) {
        templateEscolhido = "chamada_certificado_digital"; // Nome real do seu arquivo
        placeholders = [nomeCliente, "Suporte Docla"]; // Tem 2 variáveis
    }
    else if (textoLower.includes("cancelamento")) {
        templateEscolhido = "cancelamento_novo_imagem"; // Nome real do seu arquivo
        placeholders = [nomeCliente, linkExtraido]; // Tem 2 variáveis
    }
    else {
        // Se não encontrar nada, usa o de certificado como padrão ou outro que você use muito
        templateEscolhido = "chamada_certificado_digital"; 
        placeholders = [nomeCliente, "Equipe"];
    }

    return {
        json: {
            platform_id: platform_id,
            channel_id: corpo.channel_id || "67e6b384c5e6300019ecdacb",
            hsm_template_name: templateEscolhido,
            hsm_placeholders: placeholders,
            token: dadosLogin.token
        }
    };
});
